def gerar_titulo():
    """
    Gera o título 'BruteForce Simulator' em ASCII art
    usando a fonte 'slant' da biblioteca pyfiglet.

    Retorna:
        str: O título formatado em ASCII art.
    """
    return pyfiglet.figlet_format("BruteForce Simulator", font="slant")


def exibir_banner():
    """
    Exibe o banner completo no terminal:
    1. Ícone do cadeado colorido
    2. Título em ASCII art
    """
    print(ICONE_CADEADO)
    print(gerar_titulo())
